import pandas as pd, numpy as np, cv2, sys
di=pd.read_csv('demo_metadata.csv'); do=pd.read_csv('/tmp/out.csv')
img=cv2.imread('demo_rgb.png'); H,W=img.shape[:2]
fails=[]
# header/schema identical
if open('demo_metadata.csv').readline()!=open('/tmp/out.csv').readline(): fails.append('header mismatch')
if list(di.columns)!=list(do.columns): fails.append('columns differ')
if len(di)!=len(do): fails.append('row count differ')
# non-updated columns preserved verbatim
for c in ['raw_classification','main_classification','super_classification']:
    if not (di[c].fillna('') == do[c].fillna('')).all(): fails.append(f'{c} altered')
occ=np.zeros((H,W),np.int32); overlap=noncontig=rect=empty=bbad=0
for _,r in do.iterrows():
    xs=[int(v) for v in str(r['coords_x']).split(',')]; ys=[int(v) for v in str(r['coords_y']).split(',')]
    if str(r['type'])!='polyline': fails.append('type not polyline')
    if len(set(zip(xs,ys)))<=4: rect+=1
    m=np.zeros((H,W),np.uint8); cv2.fillPoly(m,[np.array(list(zip(xs,ys)),np.int32)],1)
    if m.sum()==0: empty+=1
    n,_=cv2.connectedComponents(m)
    if n>2: noncontig+=1
    overlap+=int(((occ>0)&(m>0)).sum()); occ[m>0]+=1
    if (int(min(xs)),int(max(xs)),int(min(ys)),int(max(ys)))!=(r['xmin'],r['xmax'],r['ymin'],r['ymax']): bbad+=1
if overlap: fails.append(f'overlap_px={overlap}')
if noncontig: fails.append(f'noncontig={noncontig}')
if empty: fails.append(f'empty={empty}')
if rect: fails.append(f'rectangle_masks={rect}')
if bbad: fails.append(f'bbox_mismatch={bbad}')
print('CHECKS:', 'PASS' if not fails else 'FAIL')
[print(' -',f) for f in fails]
sys.exit(1 if fails else 0)
